arguments.content:
/* Reset and Base */
*, *::before, *::after {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

:root {
    /* Colors */
    --color-primary: #6B4A3A;
    --color-primary-dark: #4A3328;
    --color-primary-light: #8B6B5B;
    --color-accent: #D4A574;
    --color-accent-warm: #E8C892;
    --color-bg: #FAF8F5;
    --color-bg-alt: #F5F2ED;
    --color-text: #2D2D2D;
    --color-text-light: #666666;
    --color-text-muted: #999999;
    --color-white: #FFFFFF;
    --color-cream: #FDF8F3;

    /* Typography */
    --font-display: 'Playfair Display', Georgia, serif;
    --font-body: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;

    /* Spacing */
    --section-padding: 120px;
    --container-padding: 24px;

    /* Transitions */
    --transition-smooth: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
    --transition-bounce: all 0.4s cubic-bezier(0.68, -0.55, 0.265, 1.55);
}

html {
    scroll-behavior: smooth;
}

body {
    font-family: var(--font-body);
    background-color: var(--color-bg);
    color: var(--color-text);
    line-height: 1.6;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
}

.container {
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 var(--container-padding);
}

/* Buttons */
.btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 14px 32px;
    font-family: var(--font-body);
    font-size: 14px;
    font-weight: 500;
    text-decoration: none;
    border-radius: 50px;
    cursor: pointer;
    transition: var(--transition-smooth);
    border: none;
    letter-spacing: 0.5px;
}

.btn-primary {
    background-color: var(--color-primary);
    color: var(--color-white);
    box-shadow: 0 4px 15px rgba(107, 74, 58, 0.3);
}

.btn-primary:hover {
    background-color: var(--color-primary-dark);
    transform: translateY(-2px);
    box-shadow: 0 6px 20px rgba(107, 74, 58, 0.4);
}

.btn-secondary {
    background-color: transparent;
    color: var(--color-white);
    border: 2px solid var(--color-white);
}

.btn-secondary:hover {
    background-color: var(--color-white);
    color: var(--color-primary);
}

.btn-outline {
    background-color: transparent;
    color: var(--color-text);
    border: 1.5px solid var(--color-text);
    padding: 10px 24px;
}

.btn-outline:hover {
    background-color: var(--color-text);
    color: var(--color-white);
}

/* Navigation */
.navbar {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    z-index: 1000;
    transition: var(--transition-smooth);
    padding: 20px 0;
}

.navbar.scrolled {
    background-color: rgba(250, 248, 245, 0.95);
    backdrop-filter: blur(20px);
    -webkit-backdrop-filter: blur(20px);
    box-shadow: 0 1px 0 rgba(0, 0, 0, 0.05);
    padding: 15px 0;
}

.navbar.scrolled .logo,
.navbar.scrolled .nav-links a {
    color: var(--color-text);
}

.nav-container {
    max-width: 1400px;
    margin: 0 auto;
    padding: 0 40px;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.logo {
    display: flex;
    align-items: center;
    gap: 10px;
    font-family: var(--font-display);
    font-size: 24px;
    font-weight: 600;
    color: var(--color-white);
    text-decoration: none;
    transition: var(--transition-smooth);
}

.logo-icon {
    width: 28px;
    height: 28px;
}

.nav-links {
    display: flex;
    align-items: center;
    gap: 40px;
}

.nav-links a {
    color: var(--color-white);
    text-decoration: none;
    font-size: 14px;
    font-weight: 500;
    letter-spacing: 0.5px;
    position: relative;
    transition: var(--transition-smooth);
}

.nav-links a:not(.btn)::after {
    content: '';
    position: absolute;
    bottom: -4px;
    left: 0;
    width: 0;
    height: 2px;
    background-color: var(--color-accent);
    transition: var(--transition-smooth);
}

.nav-links a:not(.btn):hover::after {
    width: 100%;
}

.nav-links .btn-outline:hover {
    color: var(--color-white);
    border-color: var(--color-text);
}

.navbar.scrolled .nav-links .btn-outline {
    border-color: var(--color-text);
}

.navbar.scrolled .nav-links .btn-outline:hover {
    background-color: var(--color-text);
    border-color: var(--color-text);
    color: var(--color-white);
}

.mobile-menu-btn {
    display: none;
    flex-direction: column;
    gap: 5px;
    background: none;
    border: none;
    cursor: pointer;
    padding: 5px;
}

.mobile-menu-btn span {
    display: block;
    width: 24px;
    height: 2px;
    background-color: var(--color-white);
    transition: var(--transition-smooth);
}

.navbar.scrolled .mobile-menu-btn span {
    background-color: var(--color-text);
}

/* Hero Section */
.hero {
    height: 100vh;
    min-height: 700px;
    background-image: url('https://images.unsplash.com/photo-1495474472287-4d71bcdd2085?w=1920&h=1080&fit=crop');
    background-size: cover;
    background-position: center;
    display: flex;
    align-items: center;
    justify-content: center;
    position: relative;
}

.hero-overlay {
    position: absolute;
    inset: 0;
    background: linear-gradient(
        135deg,
        rgba(45, 38, 32, 0.85) 0%,
        rgba(45, 38, 32, 0.6) 50%,
        rgba(45, 38, 32, 0.4) 100%
    );
}

.hero-content {
    position: relative;
    z-index: 1;
    text-align: center;
    max-width: 800px;
    padding: 0 24px;
    animation: fadeInUp 1s ease-out;
}

@keyframes fadeInUp {
    from {
        opacity: 0;
        transform: translateY(30px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.hero-tag {
    display: inline-block;
    font-size: 12px;
    font-weight: 600;
    letter-spacing: 3px;
    text-transform: uppercase;
    color: var(--color-accent);
    margin-bottom: 24px;
}

.hero h1 {
    font-family: var(--font-display);
    font-size: clamp(48px, 8vw, 72px);
    font-weight: 400;
    line-height: 1.1;
    color: var(--color-white);
    margin-bottom: 24px;
}

.hero-description {
    font-size: 18px;
    line-height: 1.7;
    color: rgba(255, 255, 255, 0.85);
    max-width: 600px;
    margin: 0 auto 40px;
}

.hero-buttons {
    display: flex;
    gap: 16px;
    justify-content: center;
    flex-wrap: wrap;
}

.scroll-indicator {
    position: absolute;
    bottom: 40px;
    left: 50%;
    transform: translateX(-50%);
}

.scroll-line {
    width: 2px;
    height: 60px;
    background: linear-gradient(to bottom, var(--color-accent), transparent);
    animation: scrollPulse 2s ease-in-out infinite;
}

@keyframes scrollPulse {
    0%, 100% {
        opacity: 0.4;
        transform: scaleY(0.5);
    }
    50% {
        opacity: 1;
        transform: scaleY(1);
    }
}

/* Section Styles */
.section-tag {
    display: inline-block;
    font-size: 12px;
    font-weight: 600;
    letter-spacing: 2.5px;
    text-transform: uppercase;
    color: var(--color-accent);
    margin-bottom: 16px;
}

.section-header {
    text-align: center;
    margin-bottom: 60px;
}

.section-header h2 {
    font-family: var(--font-display);
    font-size: clamp(36px, 5vw, 48px);
    font-weight: 400;
    line-height: 1.2;
    margin-bottom: 16px;
}

.section-subtitle {
    font-size: 18px;
    color: var(--color-text-light);
    max-width: 500px;
    margin: 0 auto;
}

/* About Section */
.about {
    padding: var(--section-padding) 0;
    background-color: var(--color-white);
}

.about-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 80px;
    align-items: center;
}

.about-images {
    position: relative;
    display: grid;
    grid-template-columns: 2fr 1fr;
    gap: 20px;
}

.image-card {
    border-radius: 8px;
    overflow: hidden;
}

.image-card img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.7s ease;
}

.image-card:hover img {
    transform: scale(1.05);
}

.image-1 {
    grid-row: span 2;
    aspect-ratio: 3/4;
}

.image-2 {
    aspect-ratio: 4/3;
    align-self: end;
}

.about-content {
    padding-right: 40px;
}

.about-content h2 {
    font-family: var(--font-display);
    font-size: clamp(36px, 4vw, 48px);
    font-weight: 400;
    line-height: 1.2;
    margin-bottom: 24px;
}

.about-content .section-subtitle {
    margin-bottom: 40px;
    margin-left: 0;
    text-align: left;
}

.features {
    display: flex;
    flex-direction: column;
    gap: 24px;
}

.feature {
    display: flex;
    gap: 16px;
    align-items: flex-start;
}

.feature-icon {
    width: 48px;
    height: 48px;
    min-width: 48px;
    background-color: var(--color-cream);
    border-radius: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.feature-icon svg {
    width: 24px;
    height: 24px;
    color: var(--color-primary);
}

.feature-text h3 {
    font-size: 18px;
    font-weight: 600;
    margin-bottom: 6px;
}

.feature-text p {
    font-size: 14px;
    color: var(--color-text-light);
    line-height: 1.6;
}

/* Menu Section */
.menu {
    padding: var(--section-padding) 0;
    background-color: var(--color-bg-alt);
}

.menu-tabs {
    display: flex;
    justify-content: center;
    gap: 8px;
    margin-bottom: 48px;
    flex-wrap: wrap;
}

.tab-btn {
    padding: 12px 24px;
    font-family: var(--font-body);
    font-size: 14px;
    font-weight: 500;
    background: transparent;
    border: none;
    color: var(--color-text-muted);
    cursor: pointer;
    border-radius: 50px;
    transition: var(--transition-smooth);
}

.tab-btn:hover {
    color: var(--color-text);
}

.tab-btn.active {
    background-color: var(--color-primary);
    color: var(--color-white);
}

.menu-grid {
    display: grid;
    grid-template-columns: repeat(2, 1fr);
    gap: 24px;
}

.menu-item {
    display: flex;
    gap: 20px;
    background-color: var(--color-white);
    border-radius: 12px;
    overflow: hidden;
    transition: var(--transition-smooth);
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.04);
}

.menu-item:hover {
    transform: translateY(-4px);
    box-shadow: 0 12px 32px rgba(0, 0, 0, 0.08);
}

.menu-item.hidden {
    display: none;
}

.menu-item-image {
    width: 140px;
    min-width: 140px;
    height: 140px;
    overflow: hidden;
}

.menu-item-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.5s ease;
}

.menu-item:hover .menu-item-image img {
    transform: scale(1.1);
}

.menu-item-content {
    padding: 20px 20px 20px 0;
    display: flex;
    flex-direction: column;
    flex: 1;
}

.menu-item-header {
    display: flex;
    justify-content: space-between;
    align-items: baseline;
    margin-bottom: 8px;
}

.menu-item-header h3 {
    font-size: 18px;
    font-weight: 600;
}

.price {
    font-weight: 600;
    color: var(--color-primary);
    font-size: 16px;
}

.menu-item-description {
    font-size: 14px;
    color: var(--color-text-light);
    line-height: 1.6;
}

/* Visit Section */
.visit {
    background-color: var(--color-white);
    overflow: hidden;
}

.visit-container {
    display: grid;
    grid-template-columns: 1fr 1fr;
    min-height: 700px;
}

.visit-image {
    position: relative;
    height: 100%;
}

.visit-image img {
    position: absolute;
    inset: 0;
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.visit-content {
    padding: 80px;
    display: flex;
    flex-direction: column;
    justify-content: center;
}

.visit-content h2 {
    font-family: var(--font-display);
    font-size: clamp(36px, 4vw, 48px);
    font-weight: 400;
    line-height: 1.2;
    margin-bottom: 48px;
}

.visit-info {
    display: flex;
    flex-direction: column;
    gap: 32px;
}

.info-card {
    display: flex;
    gap: 20px;
    align-items: flex-start;
}

.info-icon {
    width: 52px;
    height: 52px;
    min-width: 52px;
    background-color: var(--color-cream);
    border-radius: 12px;
    display: flex;
    align-items: center;
    justify-content: center;
}

.info-icon svg {
    width: 24px;
    height: 24px;
    color: var(--color-primary);
}

.info-text h3 {
    font-size: 16px;
    font-weight: 600;
    margin-bottom: 8px;
}

.info-text p {
    font-size: 15px;
    color: var(--color-text-light);
    line-height: 1.7;
}

/* Newsletter Section */
.newsletter {
    padding: 100px 0;
    background-color: var(--color-primary-dark);
    position: relative;
    overflow: hidden;
}

.newsletter::before {
    content: '';
    position: absolute;
    inset: 0;
    background: url('https://images.unsplash.com/photo-1447933601403-0c6688de566e?w=1920&h=600&fit=crop') center/cover;
    opacity: 0.1;
}

.newsletter-content {
    position: relative;
    z-index: 1;
    text-align: center;
    max-width: 600px;
    margin: 0 auto;
}

.newsletter h2 {
    font-family: var(--font-display);
    font-size: clamp(32px, 4vw, 42px);
    font-weight: 400;
    color: var(--color-white);
    margin-bottom: 16px;
}

.newsletter p {
    font-size: 16px;
    color: rgba(255, 255, 255, 0.7);
    margin-bottom: 40px;
}

.newsletter-form {
    display: flex;
    gap: 12px;
    max-width: 480px;
    margin: 0 auto;
}

.newsletter-form input {
    flex: 1;
    padding: 16px 24px;
    border: none;
    border-radius: 50px;
    font-family: var(--font-body);
    font-size: 15px;
    background-color: rgba(255, 255, 255, 0.1);
    color: var(--color-white);
    outline: none;
    transition: var(--transition-smooth);
}

.newsletter-form input::placeholder {
    color: rgba(255, 255, 255, 0.5);
}

.newsletter-form input:focus {
    background-color: rgba(255, 255, 255, 0.15);
    box-shadow: 0 0 0 3px rgba(212, 165, 116, 0.3);
}

.newsletter-form .btn {
    padding: 16px 32px;
    white-space: nowrap;
}

/* Footer */
.footer {
    background-color: var(--color-text);
    color: var(--color-white);
    padding: 80px 0 40px;
}

.footer-grid {
    display: grid;
    grid-template-columns: 2fr 1fr 1fr 1fr;
    gap: 60px;
    margin-bottom: 60px;
}

.footer-brand .logo {
    color: var(--color-white);
    margin-bottom: 16px;
}

.footer-tagline {
    font-size: 14px;
    color: rgba(255, 255, 255, 0.6);
    margin-bottom: 24px;
}

.social-links {
    display: flex;
    gap: 16px;
}

.social-links a {
    width: 40px;
    height: 40px;
    border-radius: 50%;
    background-color: rgba(255, 255, 255, 0.1);
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--color-white);
    transition: var(--transition-smooth);
}

.social-links a:hover {
    background-color: var(--color-accent);
    transform: translateY(-3px);
}

.social-links svg {
    width: 18px;
    height: 18px;
}

.footer-links h4 {
    font-size: 14px;
    font-weight: 600;
    letter-spacing: 1px;
    text-transform: uppercase;
    margin-bottom: 24px;
}

.footer-links ul {
    list-style: none;
}

.footer-links li {
    margin-bottom: 12px;
}

.footer-links a {
    color: rgba(255, 255, 255, 0.6);
    text-decoration: none;
    font-size: 14px;
    transition: var(--transition-smooth);
}

.footer-links a:hover {
    color: var(--color-accent);
}

.footer-bottom {
    padding-top: 40px;
    border-top: 1px solid rgba(255, 255, 255, 0.1);
    text-align: center;
}

.footer-bottom p {
    font-size: 14px;
    color: rgba(255, 255, 255, 0.5);
}

/* Responsive Design */
@media (max-width: 1024px) {
    .about-grid {
        gap: 40px;
    }

    .about-content {
        padding-right: 0;
    }

    .visit-content {
        padding: 60px 40px;
    }
}

@media (max-width: 768px) {
    :root {
        --section-padding: 80px;
    }

    .nav-container {
        padding: 0 20px;
    }

    .nav-links {
        display: none;
        position: absolute;
        top: 100%;
        left: 0;
        right: 0;
        background-color: rgba(250, 248, 245, 0.98);
        backdrop-filter: blur(20px);
        flex-direction: column;
        padding: 20px;
        gap: 16px;
    }

    .nav-links.active {
        display: flex;
    }

    .navbar.scrolled .nav-links a {
        color: var(--color-text);
    }

    .mobile-menu-btn {
        display: flex;
    }

    .about-grid {
        grid-template-columns: 1fr;
    }

    .about-images {
        order: 2;
    }

    .menu-grid {
        grid-template-columns: 1fr;
    }

    .menu-item-image {
        width: 120px;
        min-width: 120px;
        height: 120px;
    }

    .visit-container {
        grid-template-columns: 1fr;
    }

    .visit-image {
        min-height: 300px;
    }

    .visit-content {
        padding: 60px 24px;
    }

    .newsletter-form {
        flex-direction: column;
    }

    .footer-grid {
        grid-template-columns: 1fr 1fr;
        gap: 40px;
    }

    .footer-brand {
        grid-column: span 2;
    }
}

@media (max-width: 480px) {
    .hero-buttons {
        flex-direction: column;
        align-items: center;
    }

    .hero-buttons .btn {
        width: 200px;
    }

    .footer-grid {
        grid-template-columns: 1fr;
    }

    .footer-brand {
        grid-column: span 1;
    }

    .tab-btn {
        padding: 10px 16px;
        font-size: 13px;
    }
}

/* Fade animation for menu items */
@keyframes fadeIn {
    from {
        opacity: 0;
        transform: translateY(10px);
    }
    to {
        opacity: 1;
        transform: translateY(0);
    }
}

.menu-item:not(.hidden) {
    animation: fadeIn 0.4s ease-out;
}

document.addEventListener('DOMContentLoaded', function() {
    // Navigation scroll effect
    const navbar = document.querySelector('.navbar');
    let lastScrollY = window.scrollY;

    function handleScroll() {
        const currentScrollY = window.scrollY;

        // Add/remove scrolled class
        if (currentScrollY > 50) {
            navbar.classList.add('scrolled');
        } else {
            navbar.classList.remove('scrolled');
        }

        lastScrollY = currentScrollY;
    }

    window.addEventListener('scroll', handleScroll, { passive: true });

    // Mobile menu toggle
    const mobileMenuBtn = document.querySelector('.mobile-menu-btn');
    const navLinks = document.querySelector('.nav-links');

    mobileMenuBtn.addEventListener('click', function() {
        navLinks.classList.toggle('active');
        this.classList.toggle('active');

        // Animate hamburger to X
        const spans = this.querySelectorAll('span');
        if (this.classList.contains('active')) {
            spans[0].style.transform = 'rotate(45deg) translate(5px, 5px)';
            spans[1].style.opacity = '0';
            spans[2].style.transform = 'rotate(-45deg) translate(6px, -6px)';
        } else {
            spans[0].style.transform = '';
            spans[1].style.opacity = '1';
            spans[2].style.transform = '';
        }
    });

    // Close mobile menu when clicking a link
    navLinks.querySelectorAll('a').forEach(link => {
        link.addEventListener('click', function() {
            navLinks.classList.remove('active');
            mobileMenuBtn.classList.remove('active');
            const spans = mobileMenuBtn.querySelectorAll('span');
            spans[0].style.transform = '';
            spans[1].style.opacity = '1';
            spans[2].style.transform = '';
        });
    });

    // Menu tab switching
    const tabBtns = document.querySelectorAll('.tab-btn');
    const menuItems = document.querySelectorAll('.menu-item');

    tabBtns.forEach(btn => {
        btn.addEventListener('click', function() {
            const category = this.dataset.category;

            // Update active tab
            tabBtns.forEach(b => b.classList.remove('active'));
            this.classList.add('active');

            // Filter menu items
            menuItems.forEach(item => {
                if (category === 'coffee') {
                    // Show coffee items (first 3)
                    if (['Single Origin Pour Over', 'Cold Brew', 'Nitro Cold Brew'].includes(
                        item.querySelector('h3').textContent
                    )) {
                        item.classList.remove('hidden');
                    } else {
                        item.classList.add('hidden');
                    }
                } else {
                    if (item.dataset.category === category) {
                        item.classList.remove('hidden');
                    } else {
                        item.classList.add('hidden');
                    }
                }
            });
        });
    });

    // Smooth scroll for anchor links
    document.querySelectorAll('a[href^="#"]').forEach(anchor => {
        anchor.addEventListener('click', function(e) {
            e.preventDefault();
            const target = document.querySelector(this.getAttribute('href'));
            if (target) {
                const offset = 80; // Account for fixed nav
                const targetPosition = target.getBoundingClientRect().top + window.scrollY - offset;

                window.scrollTo({
                    top: targetPosition,
                    behavior: 'smooth'
                });
            }
        });
    });

    // Newsletter form
    const newsletterForm = document.querySelector('.newsletter-form');

    newsletterForm.addEventListener('submit', function(e) {
        e.preventDefault();
        const email = this.querySelector('input[type="email"]').value;

        // Simple validation and feedback
        if (email) {
            const btn = this.querySelector('button');
            const originalText = btn.textContent;

            btn.textContent = 'Subscribed!';
            btn.style.backgroundColor = '#4CAF50';

            setTimeout(() => {
                btn.textContent = originalText;
                btn.style.backgroundColor = '';
                this.reset();
            }, 3000);
        }
    });

    // Reveal animations on scroll
    const revealElements = document.querySelectorAll('.feature, .menu-item, .info-card');

    const revealOnScroll = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                entry.target.style.opacity = '1';
                entry.target.style.transform = 'translateY(0)';
            }
        });
    }, {
        threshold: 0.1,
        rootMargin: '0px 0px -50px 0px'
    });

    revealElements.forEach(el => {
        el.style.opacity = '0';
        el.style.transform = 'translateY(20px)';
        el.style.transition = 'opacity 0.6s ease, transform 0.6s ease';
        revealOnScroll.observe(el);
    });

    // Parallax effect for hero
    const hero = document.querySelector('.hero');

    window.addEventListener('scroll', function() {
        if (window.innerWidth > 768) {
            const scrollY = window.scrollY;
            const parallaxSpeed = 0.5;
            hero.style.backgroundPositionY = `${scrollY * parallaxSpeed}px`;
        }
    }, { passive: true });

    // Add hover effect for menu items
    menuItems.forEach(item => {
        item.addEventListener('mouseenter', function() {
            this.style.zIndex = '10';
        });

        item.addEventListener('mouseleave', function() {
            this.style.zIndex = '';
        });
    });

    // Lazy load images
    const lazyImages = document.querySelectorAll('img');

    const imageObserver = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                const img = entry.target;
                img.style.opacity = '0';
                img.style.transition = 'opacity 0.5s ease';

                // Ensure image is loaded
                if (img.complete) {
                    img.style.opacity = '1';
                } else {
                    img.addEventListener('load', () => {
                        img.style.opacity = '1';
                    });
                }

                imageObserver.unobserve(img);
            }
        });
    });

    lazyImages.forEach(img => imageObserver.observe(img));
});
